 inherits = "release"     # Benchmarks use same optimizations as release

 [patch.crates-io]
-# asupersync + franken-* now pulled from crates.io v0.3.0 — no patch needed.
+# asupersync + franken-* are pulled from crates.io v0.3.0 directly —
+# no sibling path patch needed.
+#
+# fastmcp-rust is temporarily force-patched to the sibling checkout
+# until its own v0.3 release propagates to crates.io. The currently
+# published fastmcp 0.2.1 on crates.io still depends on asupersync
+# 0.2.9, which would bifurcate the asupersync graph against our own
+# 0.3.0 direct dep (producing hundreds of "multiple different versions
+# of crate `asupersync`" Cx/Outcome type mismatches). Once fastmcp 0.3
+# lands on crates.io, bump the [workspace.dependencies] entries for
+# fastmcp / fastmcp-core / fastmcp-server / fastmcp-transport /
+# fastmcp-protocol to "0.3" and delete this block.
+fastmcp-rust = { path = "../fastmcp_rust/crates/fastmcp" }
+fastmcp-core = { path = "../fastmcp_rust/crates/fastmcp-core" }
+fastmcp-server = { path = "../fastmcp_rust/crates/fastmcp-server" }
+fastmcp-transport = { path = "../fastmcp_rust/crates/fastmcp-transport" }
+fastmcp-protocol = { path = "../fastmcp_rust/crates/fastmcp-protocol" }
+
 beads_rust = { path = "../beads_rust" }
 # sqlmodel/frankensqlite stack: force latest local /dp checkouts to avoid stale registry builds.
 sqlmodel = { path = "../sqlmodel_rust/crates/sqlmodel" }

